+fn buffer_to_lines(buffer: &OptimizedBuffer) -> Vec<String> {
+    let (w, h) = buffer.size();
+    let mut lines = Vec::new();
+    for y in 0..h {
+        let mut line = String::new();
+        for x in 0..w {
+            let cell = buffer.get(x, y).unwrap();
+            line.push_str(&cell.content.as_str());
+        }
+        lines.push(line);
+    }
+    lines
